-- 排他制御テーブル
CREATE TABLE USERS (
    USER_ID CHAR(6) NOT NULL,
    -- 主キー以外の業務データは省略
    VERSION NUMBER(10) NOT NULL,
    PRIMARY KEY (USER_ID)
)

// 排他制御テーブルUSERSに対応するクラス
// ExclusiveControlContextを継承
public class UsersExclusiveControl extends ExclusiveControlContext {

    // 排他制御テーブルの主キーを列挙型で定義
    private enum PK { USER_ID }

    // 主キーの値を受け取るコンストラクタを定義
    public UsersExclusiveControl(String userId) {

        // 親クラスのsetTableNameメソッドでテーブル名を設定
        setTableName("USERS");

        // 親クラスのsetVersionColumnNameメソッドでバージョン番号カラム名を設定
        setVersionColumnName("VERSION");

        // 親クラスのsetPrimaryKeyColumnNamesメソッドに列挙型のvaluesメソッドで
        // すべての主キー列挙型を設定
        setPrimaryKeyColumnNames(PK.values());

        // 親クラスのappendConditionメソッドで主キーの値を追加
        appendCondition(PK.USER_ID, userId);
    }
}

